const period = $json.period;
const now = DateTime.now().setZone('Europe/Berlin');
let currentStart, currentEnd, previousStart, previousEnd, periodLabel, subjectSuffix, unit;

if (period === 'weekly') {
  const thisMonday = now.startOf('week');
  const cs = thisMonday.minus({ weeks: 1 });
  const ce = cs.plus({ weeks: 1 }).minus({ milliseconds: 1 });
  currentStart = cs.toISO();
  currentEnd = ce.toISO();
  previousStart = cs.minus({ weeks: 1 }).toISO();
  previousEnd = cs.minus({ milliseconds: 1 }).toISO();
  periodLabel = `Wochenreport KW${cs.weekNumber} / ${cs.weekYear}`;
  subjectSuffix = `KW${cs.weekNumber} ${cs.weekYear}`;
  unit = 'day';
} else {
  const cs = now.minus({ months: 1 }).startOf('month');
  const ce = cs.endOf('month');
  currentStart = cs.toISO();
  currentEnd = ce.toISO();
  const ps = cs.minus({ months: 1 });
  previousStart = ps.toISO();
  previousEnd = ps.endOf('month').toISO();
  const monthName = cs.setLocale('de').toFormat('LLLL yyyy');
  periodLabel = `Monatsreport ${monthName}`;
  subjectSuffix = monthName;
  unit = 'day';
}

const toMs = (s) => new Date(s).getTime();
return [{
  json: {
    period, periodLabel, subjectSuffix,
    currentStart, currentEnd, previousStart, previousEnd,
    currentStartMs: toMs(currentStart),
    currentEndMs: toMs(currentEnd),
    previousStartMs: toMs(previousStart),
    previousEndMs: toMs(previousEnd),
    unit, timezone: 'Europe/Berlin',
  },
}];

const period = $('Compute Period').first().json;
const stats = $('Stats').first().json;
const pageviews = $('Pageviews').first().json;
const metrics = {
  path: $('Metrics path').first().json,
  referrer: $('Metrics referrer').first().json,
  country: $('Metrics country').first().json,
  channel: $('Metrics channel').first().json,
  device: $('Metrics device').first().json,
  event: $('Metrics event').first().json,
  previousPath: $('Metrics path (prev)').first().json,
  previousReferrer: $('Metrics referrer (prev)').first().json,
};
return [{ json: { period, stats, pageviews, metrics } }];

let raw = ($input.first().json.output ?? '').toString();
raw = raw.replace(/```html\s*/gi, '').replace(/```\s*$/g, '');
raw = raw.replace(/^\s*Hier ist[^\n]*\n/i, '');
const startTags = ['<table', '<!doctype', '<!DOCTYPE', '<html'];
const positions = startTags.map((t) => raw.indexOf(t)).filter((i) => i >= 0);
if (positions.length > 0) raw = raw.slice(Math.min(...positions));
raw = raw.replace(/\n{3,}/g, '\n\n').trim();

const ctx = $('Compute Period').first().json;
return [{ json: { html: raw, subjectSuffix: ctx.subjectSuffix, periodLabel: ctx.periodLabel } }];
